import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);

  const [tab, setTab] = useState('users');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    const [u, p, c] = await Promise.all([
      API.get('/admin/users'),
      API.get('/admin/posts'),
      API.get('/admin/comments'),
    ]);

    setUsers(u.data);
    setPosts(p.data);
    setComments(c.data);
  };

  // ================= USERS =================
  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  // ================= POSTS =================
  const removePost = async (id) => {
    const { data } = await API.put(`/admin/posts/${id}/remove`);
    setPosts(posts.map(p => (p._id === id ? data : p)));
  };

  const restorePost = async (id) => {
    const { data } = await API.put(`/admin/posts/${id}/restore`);
    setPosts(posts.map(p => (p._id === id ? data : p)));
  };

  // ================= COMMENTS =================
  const removeComment = async (id) => {
    const { data } = await API.put(`/admin/comments/${id}/remove`);
    setComments(comments.map(c => (c._id === id ? data : c)));
  };

  const restoreComment = async (id) => {
    const { data } = await API.put(`/admin/comments/${id}/restore`);
    setComments(comments.map(c => (c._id === id ? data : c)));
  };

  // ================= VIEW POST =================
  const viewPost = (postId) => {
    navigate(`/post/${postId}`);
  };

  const isDark = document.body.classList.contains("dark-mode");

  const styles = {
    page: {
      backgroundColor: isDark ? '#560032' : '#FAE8ED',
      minHeight: '100vh',
      padding: '30px',
      fontFamily: 'Georgia',
    },
    container: {
      maxWidth: '1100px',
      margin: 'auto',
      backgroundColor: isDark ? '#2e091e' : '#f7c6d9',
      padding: '30px',
      borderRadius: '20px',
    },
    tabs: {
      display: 'flex',
      gap: '10px',
      marginBottom: '20px',
      justifyContent: 'center',
    },
    tabBtn: {
      padding: '10px 20px',
      border: 'none',
      borderRadius: '20px',
      cursor: 'pointer',
      fontWeight: 'bold',
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse',
      marginTop: '10px',
    },
    th: {
      backgroundColor: 'rgb(12,75,52)',
      color: '#fff',
      padding: '10px',
      textAlign: 'left',
    },
    td: {
      padding: '10px',
      borderBottom: '1px solid #ddd',
    },
    btn: {
      padding: '6px 10px',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      marginRight: '5px',
    },
    danger: {
      backgroundColor: '#eda0ae',
      color: '#fff',
    },
    restore: {
      backgroundColor: '#4CAF50',
      color: '#fff',
    },
    view: {
      backgroundColor: '#6c63ff',
      color: '#fff',
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>

        {/* TABS */}
        <div style={styles.tabs}>
          <button style={styles.tabBtn} onClick={() => setTab('users')}>
            Users ({users.length})
          </button>

          <button style={styles.tabBtn} onClick={() => setTab('posts')}>
            Posts ({posts.length})
          </button>

          <button style={styles.tabBtn} onClick={() => setTab('comments')}>
            Comments ({comments.length})
          </button>
        </div>

        {/* USERS */}
        {tab === 'users' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Name</th>
                <th style={styles.th}>Email</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, ...styles.danger }}
                      onClick={() => toggleStatus(u._id)}
                    >
                      Toggle
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* POSTS */}
        {tab === 'posts' && (
          <table style={styles.table}>
            <tbody>
              {posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.status}</td>
                  <td style={styles.td}>

                    {/* VIEW POST */}
                    <button
                      style={{ ...styles.btn, ...styles.view }}
                      onClick={() => viewPost(p._id)}
                    >
                      View
                    </button>

                    {/* REMOVE / RESTORE */}
                    {p.status === 'published' ? (
                      <button
                        style={{ ...styles.btn, ...styles.danger }}
                        onClick={() => removePost(p._id)}
                      >
                        Remove
                      </button>
                    ) : (
                      <button
                        style={{ ...styles.btn, ...styles.restore }}
                        onClick={() => restorePost(p._id)}
                      >
                        Undo
                      </button>
                    )}

                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* COMMENTS */}
        {tab === 'comments' && (
          <table style={styles.table}>
            <tbody>
              {comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.post?.title}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>

                    {/* VIEW CONTEXT */}
                    <button
                      style={{ ...styles.btn, ...styles.view }}
                      onClick={() => viewPost(c.post?._id)}
                    >
                      View Post
                    </button>

                    {/* REMOVE / RESTORE COMMENT */}
                    {c.status !== 'removed' ? (
                      <button
                        style={{ ...styles.btn, ...styles.danger }}
                        onClick={() => removeComment(c._id)}
                      >
                        Delete
                      </button>
                    ) : (
                      <button
                        style={{ ...styles.btn, ...styles.restore }}
                        onClick={() => restoreComment(c._id)}
                      >
                        Undo
                      </button>
                    )}

                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

      </div>
    </div>
  );
};

export default AdminPage;
